+/**
+ * Notification history service for logging and querying sent notifications.
+ *
+ * Integrates with NotificationService via setter injection. Every notification
+ * processed (sent, failed, or blocked) is logged for audit and query purposes.
+ */
+
+import type { NotificationLogRepository } from '../repositories/notification-log.repository.js';
+import type {
+  NotificationLog,
+  NotificationLogQuery,
+  DeliveryStatus,
+} from '../models/notification-log.js';
+import type { NotificationPayload, NotificationResult } from '../models/notification.js';
+import { Logger } from '../utils/logger.js';
+
+let nextLogId = 1;
+
+function generateLogId(): string {
+  return `nlog-${String(nextLogId++).padStart(4, '0')}`;
+}
+
+export function resetLogIdCounter(): void {
+  nextLogId = 1;
+}
+
+export class NotificationHistoryService {
+  private logger = new Logger('NotificationHistoryService');
+
+  constructor(private repository: NotificationLogRepository) {}
+
+  /**
+   * Log a notification that was processed by the notification service.
+   */
+  logNotification(
+    notificationId: string,
+    payload: NotificationPayload,
+    status: DeliveryStatus,
+    error?: string,
+  ): NotificationLog {
+    const log: NotificationLog = {
+      id: generateLogId(),
+      notificationId,
+      recipient: payload.recipient,
+      channel: payload.channel,
+      type: payload.type,
+      priority: payload.priority,
+      subject: payload.subject,
+      status,
+      error,
+      metadata: payload.metadata,
+      createdAt: new Date(),
+    };
+
+    this.repository.save(log);
+    this.logger.info(
+      `Logged notification ${notificationId}: ${status} via ${payload.channel} to ${payload.recipient}`,
+    );
+    return log;
+  }
+
+  /**
+   * Log a notification result from the notification service.
+   * Convenience method that derives status from the result.
+   */
+  logResult(
+    notificationId: string,
+    payload: NotificationPayload,
+    result: NotificationResult,
+  ): NotificationLog {
+    const status: DeliveryStatus = result.success ? 'sent' : 'failed';
+    return this.logNotification(notificationId, payload, status, result.error);
+  }
+
+  /**
+   * Query notification history with flexible filters.
+   */
+  query(filters: NotificationLogQuery): NotificationLog[] {
+    return this.repository.findAll((log) => {
+      if (filters.recipient && log.recipient !== filters.recipient) return false;
+      if (filters.channel && log.channel !== filters.channel) return false;
+      if (filters.type && log.type !== filters.type) return false;
+      if (filters.status && log.status !== filters.status) return false;
+      if (filters.startDate && log.createdAt < filters.startDate) return false;
+      if (filters.endDate && log.createdAt > filters.endDate) return false;
+      return true;
+    });
+  }
+
+  /**
+   * Get all logs for a specific recipient.
+   */
+  getByRecipient(recipient: string): NotificationLog[] {
+    return this.repository.findByRecipient(recipient);
+  }
+
+  /**
+   * Get all logs for a specific notification type.
+   */
+  getByType(type: NotificationLog['type']): NotificationLog[] {
+    return this.repository.findByType(type);
+  }
+
+  /**
+   * Get all logs within a date range.
+   */
+  getByDateRange(startDate: Date, endDate: Date): NotificationLog[] {
+    return this.repository.findByDateRange(startDate, endDate);
+  }
+
+  /**
+   * Get a single log entry by ID.
+   */
+  getById(id: string): NotificationLog | undefined {
+    return this.repository.findById(id);
+  }
+
+  /**
+   * Get total count of logged notifications.
+   */
+  getCount(): number {
+    return this.repository.count();
+  }
+}

