/**
 * Notification log model for tracking sent notifications.
 *
 * Captures delivery details for every notification processed by the system,
 * enabling audit trails and history queries.
 */

import type { NotificationChannel, NotificationPriority, NotificationType } from './notification.js';

export type DeliveryStatus = 'sent' | 'failed' | 'blocked';

export interface NotificationLog {
  id: string;
  notificationId: string;
  recipient: string;
  channel: NotificationChannel;
  type: NotificationType;
  priority: NotificationPriority;
  subject: string;
  status: DeliveryStatus;
  error?: string;
  metadata?: Record<string, unknown>;
  createdAt: Date;
}

export interface NotificationLogQuery {
  recipient?: string;
  channel?: NotificationChannel;
  type?: NotificationType;
  status?: DeliveryStatus;
  startDate?: Date;
  endDate?: Date;
}

/**
 * Repository for NotificationLog data access.
 *
 * Extends BaseRepository with log-specific query methods.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { NotificationLog, DeliveryStatus } from '../models/notification-log.js';
import type { NotificationChannel, NotificationPriority, NotificationType } from '../models/notification.js';
import { BaseRepository } from './base.repository.js';

export class NotificationLogRepository extends BaseRepository<NotificationLog> {
  constructor(db: Database) {
    super(db, 'notification_logs');
  }

  protected toDomain(record: DatabaseRecord): NotificationLog {
    return {
      id: record['id'] as string,
      notificationId: record['notificationId'] as string,
      recipient: record['recipient'] as string,
      channel: record['channel'] as NotificationChannel,
      type: record['type'] as NotificationType,
      priority: record['priority'] as NotificationPriority,
      subject: record['subject'] as string,
      status: record['status'] as DeliveryStatus,
      error: record['error'] as string | undefined,
      metadata: record['metadata'] ? JSON.parse(record['metadata'] as string) as Record<string, unknown> : undefined,
      createdAt: new Date(record['createdAt'] as string),
    };
  }

  protected toRecord(entity: NotificationLog): DatabaseRecord {
    return {
      id: entity.id,
      notificationId: entity.notificationId,
      recipient: entity.recipient,
      channel: entity.channel,
      type: entity.type,
      priority: entity.priority,
      subject: entity.subject,
      status: entity.status,
      error: entity.error,
      metadata: entity.metadata ? JSON.stringify(entity.metadata) : undefined,
      createdAt: entity.createdAt.toISOString(),
    };
  }

  findByRecipient(recipient: string): NotificationLog[] {
    return this.findAll((log) => log.recipient === recipient);
  }

  findByType(type: NotificationType): NotificationLog[] {
    return this.findAll((log) => log.type === type);
  }

  findByChannel(channel: NotificationChannel): NotificationLog[] {
    return this.findAll((log) => log.channel === channel);
  }

  findByStatus(status: DeliveryStatus): NotificationLog[] {
    return this.findAll((log) => log.status === status);
  }

  findByDateRange(startDate: Date, endDate: Date): NotificationLog[] {
    return this.findAll(
      (log) => log.createdAt >= startDate && log.createdAt <= endDate,
    );
  }
}

/**
 * Notification history service for logging and querying sent notifications.
 *
 * Integrates with NotificationService via setter injection. Every notification
 * processed (sent, failed, or blocked) is logged for audit and query purposes.
 */

import type { NotificationLogRepository } from '../repositories/notification-log.repository.js';
import type {
  NotificationLog,
  NotificationLogQuery,
  DeliveryStatus,
} from '../models/notification-log.js';
import type { NotificationPayload, NotificationResult } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

let nextLogId = 1;

function generateLogId(): string {
  return `nlog-${String(nextLogId++).padStart(4, '0')}`;
}

export function resetLogIdCounter(): void {
  nextLogId = 1;
}

export class NotificationHistoryService {
  private logger = new Logger('NotificationHistoryService');

  constructor(private repository: NotificationLogRepository) {}

  /**
   * Log a notification that was processed by the notification service.
   */
  logNotification(
    notificationId: string,
    payload: NotificationPayload,
    status: DeliveryStatus,
    error?: string,
  ): NotificationLog {
    const log: NotificationLog = {
      id: generateLogId(),
      notificationId,
      recipient: payload.recipient,
      channel: payload.channel,
      type: payload.type,
      priority: payload.priority,
      subject: payload.subject,
      status,
      error,
      metadata: payload.metadata,
      createdAt: new Date(),
    };

    this.repository.save(log);
    this.logger.info(
      `Logged notification ${notificationId}: ${status} via ${payload.channel} to ${payload.recipient}`,
    );
    return log;
  }

  /**
   * Log a notification result from the notification service.
   * Convenience method that derives status from the result.
   */
  logResult(
    notificationId: string,
    payload: NotificationPayload,
    result: NotificationResult,
  ): NotificationLog {
    const status: DeliveryStatus = result.success ? 'sent' : 'failed';
    return this.logNotification(notificationId, payload, status, result.error);
  }

  /**
   * Query notification history with flexible filters.
   */
  query(filters: NotificationLogQuery): NotificationLog[] {
    return this.repository.findAll((log) => {
      if (filters.recipient && log.recipient !== filters.recipient) return false;
      if (filters.channel && log.channel !== filters.channel) return false;
      if (filters.type && log.type !== filters.type) return false;
      if (filters.status && log.status !== filters.status) return false;
      if (filters.startDate && log.createdAt < filters.startDate) return false;
      if (filters.endDate && log.createdAt > filters.endDate) return false;
      return true;
    });
  }

  /**
   * Get all logs for a specific recipient.
   */
  getByRecipient(recipient: string): NotificationLog[] {
    return this.repository.findByRecipient(recipient);
  }

  /**
   * Get all logs for a specific notification type.
   */
  getByType(type: NotificationLog['type']): NotificationLog[] {
    return this.repository.findByType(type);
  }

  /**
   * Get all logs within a date range.
   */
  getByDateRange(startDate: Date, endDate: Date): NotificationLog[] {
    return this.repository.findByDateRange(startDate, endDate);
  }

  /**
   * Get a single log entry by ID.
   */
  getById(id: string): NotificationLog | undefined {
    return this.repository.findById(id);
  }

  /**
   * Get total count of logged notifications.
   */
  getCount(): number {
    return this.repository.count();
  }
}

