import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { EventBus } from '../../src/events/event-bus.js';
import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
import {
  NotificationHistoryService,
  resetLogIdCounter,
} from '../../src/services/notification-history.service.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';
import type { OrderCreatedEvent } from '../../src/events/event-types.js';

describe('NotificationHistoryService', () => {
  let db: Database;
  let repository: NotificationLogRepository;
  let historyService: NotificationHistoryService;

  beforeEach(() => {
    db = new Database();
    repository = new NotificationLogRepository(db);
    historyService = new NotificationHistoryService(repository);
    resetLogIdCounter();
  });

  const makePayload = (overrides?: Partial<NotificationPayload>): NotificationPayload => ({
    recipient: 'alice@example.com',
    subject: 'Test Subject',
    body: 'Test body',
    channel: 'email',
    type: 'order_confirmation',
    priority: 'normal',
    metadata: { userId: 'user-1', orderId: 'order-1' },
    ...overrides,
  });

  describe('logNotification', () => {
    it('should log a sent notification', () => {
      const log = historyService.logNotification('notif-0001', makePayload(), 'sent');

      expect(log.id).toBe('nlog-0001');
      expect(log.notificationId).toBe('notif-0001');
      expect(log.recipient).toBe('alice@example.com');
      expect(log.channel).toBe('email');
      expect(log.type).toBe('order_confirmation');
      expect(log.priority).toBe('normal');
      expect(log.subject).toBe('Test Subject');
      expect(log.status).toBe('sent');
      expect(log.createdAt).toBeInstanceOf(Date);
    });

    it('should log a failed notification with error', () => {
      const log = historyService.logNotification(
        'notif-0001',
        makePayload(),
        'failed',
        'Connection timeout',
      );

      expect(log.status).toBe('failed');
      expect(log.error).toBe('Connection timeout');
    });

    it('should log a blocked notification', () => {
      const log = historyService.logNotification('blocked', makePayload(), 'blocked');

      expect(log.status).toBe('blocked');
    });

    it('should persist metadata', () => {
      historyService.logNotification(
        'notif-0001',
        makePayload({ metadata: { userId: 'user-1', custom: 'data' } }),
        'sent',
      );

      const retrieved = historyService.getById('nlog-0001');
      expect(retrieved?.metadata).toEqual({ userId: 'user-1', custom: 'data' });
    });

    it('should generate sequential log IDs', () => {
      const log1 = historyService.logNotification('notif-0001', makePayload(), 'sent');
      const log2 = historyService.logNotification('notif-0002', makePayload(), 'sent');

      expect(log1.id).toBe('nlog-0001');
      expect(log2.id).toBe('nlog-0002');
    });
  });

  describe('logResult', () => {
    it('should log a successful result as sent', () => {
      const log = historyService.logResult('notif-0001', makePayload(), {
        success: true,
      });

      expect(log.status).toBe('sent');
      expect(log.error).toBeUndefined();
    });

    it('should log a failed result with error', () => {
      const log = historyService.logResult('notif-0001', makePayload(), {
        success: false,
        error: 'Adapter error',
      });

      expect(log.status).toBe('failed');
      expect(log.error).toBe('Adapter error');
    });
  });

  describe('query', () => {
    beforeEach(() => {
      historyService.logNotification('n1', makePayload(), 'sent');
      historyService.logNotification(
        'n2',
        makePayload({ recipient: 'bob@example.com', type: 'order_status_update', channel: 'webhook' }),
        'failed',
        'Timeout',
      );
      historyService.logNotification(
        'n3',
        makePayload({ recipient: 'alice@example.com', type: 'system_alert' }),
        'sent',
      );
    });

    it('should filter by recipient', () => {
      const results = historyService.query({ recipient: 'alice@example.com' });
      expect(results).toHaveLength(2);
    });

    it('should filter by type', () => {
      const results = historyService.query({ type: 'order_status_update' });
      expect(results).toHaveLength(1);
      expect(results[0]?.recipient).toBe('bob@example.com');
    });

    it('should filter by channel', () => {
      const results = historyService.query({ channel: 'webhook' });
      expect(results).toHaveLength(1);
    });

    it('should filter by status', () => {
      const results = historyService.query({ status: 'failed' });
      expect(results).toHaveLength(1);
      expect(results[0]?.error).toBe('Timeout');
    });

    it('should filter by date range', () => {
      const now = new Date();
      const past = new Date(now.getTime() - 60000);
      const future = new Date(now.getTime() + 60000);

      const results = historyService.query({ startDate: past, endDate: future });
      expect(results).toHaveLength(3);
    });

    it('should combine multiple filters', () => {
      const results = historyService.query({
        recipient: 'alice@example.com',
        type: 'order_confirmation',
      });
      expect(results).toHaveLength(1);
    });

    it('should return empty array for no matches', () => {
      const results = historyService.query({ recipient: 'nobody@example.com' });
      expect(results).toHaveLength(0);
    });

    it('should return all logs with empty filter', () => {
      const results = historyService.query({});
      expect(results).toHaveLength(3);
    });
  });

  describe('getByRecipient', () => {
    it('should return logs for a specific recipient', () => {
      historyService.logNotification('n1', makePayload(), 'sent');
      historyService.logNotification(
        'n2',
        makePayload({ recipient: 'bob@example.com' }),
        'sent',
      );

      const results = historyService.getByRecipient('alice@example.com');
      expect(results).toHaveLength(1);
      expect(results[0]?.recipient).toBe('alice@example.com');
    });
  });

  describe('getByType', () => {
    it('should return logs for a specific type', () => {
      historyService.logNotification('n1', makePayload(), 'sent');
      historyService.logNotification(
        'n2',
        makePayload({ type: 'system_alert' }),
        'sent',
      );

      const results = historyService.getByType('order_confirmation');
      expect(results).toHaveLength(1);
    });
  });

  describe('getByDateRange', () => {
    it('should return logs within date range', () => {
      historyService.logNotification('n1', makePayload(), 'sent');

      const now = new Date();
      const past = new Date(now.getTime() - 60000);
      const future = new Date(now.getTime() + 60000);

      expect(historyService.getByDateRange(past, future)).toHaveLength(1);
    });

    it('should exclude logs outside date range', () => {
      historyService.logNotification('n1', makePayload(), 'sent');

      const farFuture1 = new Date('2099-01-01');
      const farFuture2 = new Date('2099-12-31');

      expect(historyService.getByDateRange(farFuture1, farFuture2)).toHaveLength(0);
    });
  });

  describe('getCount', () => {
    it('should return 0 when empty', () => {
      expect(historyService.getCount()).toBe(0);
    });

    it('should return correct count', () => {
      historyService.logNotification('n1', makePayload(), 'sent');
      historyService.logNotification('n2', makePayload(), 'failed', 'err');

      expect(historyService.getCount()).toBe(2);
    });
  });

  describe('getById', () => {
    it('should return a log by ID', () => {
      historyService.logNotification('n1', makePayload(), 'sent');

      const log = historyService.getById('nlog-0001');
      expect(log).toBeDefined();
      expect(log?.notificationId).toBe('n1');
    });

    it('should return undefined for non-existent ID', () => {
      expect(historyService.getById('nlog-9999')).toBeUndefined();
    });
  });
});

describe('NotificationService + NotificationHistoryService integration', () => {
  let eventBus: EventBus;
  let notificationService: NotificationService;
  let historyService: NotificationHistoryService;
  let emailAdapter: EmailAdapter;

  beforeEach(() => {
    eventBus = new EventBus();
    notificationService = new NotificationService(eventBus);
    emailAdapter = new EmailAdapter();
    notificationService.registerAdapter(emailAdapter);

    const db = new Database();
    const repository = new NotificationLogRepository(db);
    historyService = new NotificationHistoryService(repository);
    notificationService.setHistoryService(historyService);

    resetNotificationIdCounter();
    resetLogIdCounter();
  });

  it('should log notifications sent via EventBus', async () => {
    const event: OrderCreatedEvent = {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    expect(historyService.getCount()).toBe(1);
    const logs = historyService.getByRecipient('alice@example.com');
    expect(logs).toHaveLength(1);
    expect(logs[0]?.status).toBe('sent');
    expect(logs[0]?.channel).toBe('email');
    expect(logs[0]?.type).toBe('order_confirmation');
  });

  it('should log failed notifications when no adapter registered', async () => {
    const serviceNoAdapter = new NotificationService(new EventBus());
    serviceNoAdapter.setHistoryService(historyService);

    await serviceNoAdapter.sendNotification({
      recipient: 'test@example.com',
      subject: 'Test',
      body: 'Body',
      channel: 'sms',
      type: 'system_alert',
      priority: 'normal',
    });

    expect(historyService.getCount()).toBe(1);
    const logs = historyService.query({ status: 'failed' });
    expect(logs).toHaveLength(1);
    expect(logs[0]?.error).toContain('No adapter for channel');
  });

  it('should log directly sent notifications', async () => {
    await notificationService.sendNotification({
      recipient: 'bob@example.com',
      subject: 'Direct',
      body: 'Direct body',
      channel: 'email',
      type: 'system_alert',
      priority: 'high',
    });

    const logs = historyService.getByRecipient('bob@example.com');
    expect(logs).toHaveLength(1);
    expect(logs[0]?.status).toBe('sent');
    expect(logs[0]?.priority).toBe('high');
  });

  it('should work without history service (backward compatible)', async () => {
    const plainService = new NotificationService(new EventBus());
    plainService.registerAdapter(new EmailAdapter());

    const result = await plainService.sendNotification({
      recipient: 'test@example.com',
      subject: 'Test',
      body: 'Body',
      channel: 'email',
      type: 'system_alert',
      priority: 'normal',
    });

    expect(result.success).toBe(true);
  });
});
